import type { IconProps } from "@/icons/types"

/**
 * Monochrome brand logos for the /stack page.
 *
 * Each logo follows the repo icon convention (see `src/icons/*`): it takes
 * `IconProps`, renders a 24x24 `viewBox` SVG, and uses `fill="currentColor"`
 * so the mark inherits the surrounding text color and stays monochrome in
 * both light and dark themes.
 *
 * Brand glyphs sourced from Simple Icons (https://simpleicons.org). `kitcn`
 * has no published mark, so it uses a typographic monogram.
 */

function BrandSvg({
  size = "1em",
  title,
  path,
  ...props
}: IconProps & { title: string; path: string }) {
  return (
    <svg
      fill="currentColor"
      height={size}
      role="img"
      viewBox="0 0 24 24"
      width={size}
      xmlns="http://www.w3.org/2000/svg"
      {...props}
    >
      <title>{title}</title>
      <path d={path} />
    </svg>
  )
}

